class BankAccount {
    // Private data members (Encapsulation)
    private String  name;
    private String  accountNumber;
    private double  balance;

    // Constructor
    public BankAccount(String name, String accountNumber, double balance) {
        this.name          = name;
        this.accountNumber = accountNumber;
        this.balance       = balance;
    }

    // Deposit method
    public void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
            System.out.println(amount + " deposited. New balance: " + balance);
        } else {
            System.out.println("Invalid deposit amount.");
        }
    }

    // Withdraw method (with balance check)
    public void withdraw(double amount) {
        if (amount > balance) {
            System.out.println("Insufficient balance!");
        } else if (amount <= 0) {
            System.out.println("Invalid withdrawal amount.");
        } else {
            balance -= amount;
            System.out.println(amount + " withdrawn. New balance: " + balance);
        }
    }

    // Display account details
    public void display() {
        System.out.println("--- Account Details ---");
        System.out.println("Name    : " + name);
        System.out.println("Acc No  : " + accountNumber);
        System.out.println("Balance : " + balance);
    }

    // Main method
    public static void main(String[] args) {
        BankAccount acc = new BankAccount("Rahim", "BD-1001", 5000);
        acc.display();
        acc.deposit(2000);
        acc.withdraw(1000);
        acc.withdraw(9000);  // Should show: Insufficient balance!
        acc.display();
    }
}

// Separate definition (recommended)
struct Date {
    int day, month, year;
};

struct Student {
    char name[50];
    int  roll;
    struct Date dob;   // nested struct
};

int main() {
    struct Student s;
    s.roll        = 101;
    s.dob.day     = 15;   // nested access
    s.dob.month   = 8;
    s.dob.year    = 2000;

    printf("%d/%d/%d\n",
           s.dob.day, s.dob.month, s.dob.year);
    // Output: 15/8/2000
    return 0;
}

